if(!defined('ABSPATH'))exit;
final class MJL_Native_Renos{
 const FLAG='_mjl_native_elementor_managed';
 private $logo='data:image/png;base64,...';
 public function __construct(){add_action('admin_menu',[$this,'menu']);add_action('admin_post_mjl_native_build',[$this,'build']);add_action('wp_enqueue_scripts',[$this,'css']);}
 public function menu(){add_management_page('MJL Native Elementor Pages','MJL Native Elementor Pages','manage_options','mjl-native-elementor',[$this,'screen']);}
 public function screen(){echo '<div class="wrap"><h1>MJL Native Elementor Pages</h1><p>Creates native Elementor containers and widgets. Existing MJL builder pages are refreshed as drafts.</p><form method="post" action="'.esc_url(admin_url('admin-post.php')).'"><input type="hidden" name="action" value="mjl_native_build">';wp_nonce_field('mjl_native_build');submit_button('Build / Refresh Native Elementor Pages');echo '</form></div>';}
 private function id($s){return substr(md5($s.wp_rand()),0,8);} private function w($type,$settings,$s='w'){return ['id'=>$this->id($s),'elType'=>'widget','widgetType'=>$type,'isInner'=>false,'settings'=>$settings,'elements'=>[]];} private function c($class,$elements=[],$settings=[]){return ['id'=>$this->id($class),'elType'=>'container','isInner'=>false,'settings'=>array_merge(['css_classes'=>$class],$settings),'elements'=>$elements];}
 private function h($t,$tag='h2',$cl=''){return $this->w('heading',['title'=>$t,'header_size'=>$tag,'css_classes'=>$cl],'h');} private function t($html,$cl=''){return $this->w('text-editor',['editor'=>$html,'css_classes'=>$cl],'t');} private function b($t,$url,$cl='mjl-btn'){return $this->w('button',['text'=>$t,'link'=>['url'=>$url],'css_classes'=>$cl],'b');} private function img($url,$alt,$cl=''){return $this->w('image',['image'=>['url'=>$url,'id'=>0,'alt'=>$alt],'image_size'=>'full','css_classes'=>$cl],'i');}
 private function u($s){return home_url('/'.$s.'/');}
 private function pages(){return [
 'renovations'=>['Home Renovations','MJL RENOVATIONS','Renovations Designed Around the Way You Live.','Thoughtful planning. Premium craftsmanship. Beautiful spaces built to perform for years.','https://images.unsplash.com/photo-1600566753190-17f0baa2a6c3?auto=format&fit=crop&w=2000&q=90'],
 'kitchen-renovations'=>['Kitchen Renovations','KITCHEN RENOVATIONS','A Kitchen Designed Around Real Life.','Purposeful layouts, cabinetry, surfaces, lighting and structural changes brought together as one complete renovation.','https://images.unsplash.com/photo-1556912167-f556f1f39fdf?auto=format&fit=crop&w=2000&q=90'],
 'bathroom-renovations'=>['Bathroom Renovations','BATHROOM RENOVATIONS','A Better Start and Finish to Every Day.','Durable waterproofing, thoughtful storage and refined finishes for bathrooms designed to perform.','https://images.unsplash.com/photo-1620626011761-996317b8d101?auto=format&fit=crop&w=2000&q=90'],
 'basement-renovations'=>['Basement Renovations','BASEMENT RENOVATIONS','Turn Underused Space Into Valuable Living Space.','Comfortable lower levels for family life, entertaining, work, fitness and guests.','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=2000&q=90'],
 'whole-home-renovations'=>['Whole Home Renovations','WHOLE HOME & FULL GUT RENOVATIONS','Rebuild the Home You Love Into the Home You Need.','Integrated planning for major transformations and complete interior rebuilds.','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=2000&q=90'],
 'custom-home-building'=>['Custom Home Building','CUSTOM HOME BUILDING','Build Deliberately From the Ground Up.','Practical construction thinking, accountable management and quality control from planning through turnover.','https://images.unsplash.com/photo-1600047509807-ba8f99d2cdde?auto=format&fit=crop&w=2000&q=90'],
 'renovation-process'=>['Our Renovation Process','OUR PROCESS','A Clearer Path From Idea to Completion.','Major projects become manageable when decisions happen in the right order.','https://images.unsplash.com/photo-1503387762-592deb58ef4e?auto=format&fit=crop&w=2000&q=90'],
 'renovation-portfolio'=>['Renovation Portfolio','OUR WORK','Real Projects. Thoughtful Details.','A portfolio framework ready for authentic MJL project photography and case studies.','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=2000&q=90'],
 'about-mjl-renovations'=>['About MJL Renovations','ABOUT MJL','Quality Work Requires More Than Skilled Hands.','Hands-on building experience backed by planning, communication and accountability.','https://images.unsplash.com/photo-1504917595217-d4dc5ebe6122?auto=format&fit=crop&w=2000&q=90'],
 'renovation-reviews'=>['Client Reviews','CLIENT EXPERIENCE','Trust Is Earned During the Work.','Replace the editable review cards with verified Google, Facebook or direct client reviews.','https://images.unsplash.com/photo-1497366754035-f200968a6e72?auto=format&fit=crop&w=2000&q=90'],
 'renovation-contact'=>['Start Your Renovation','CONTACT MJL','Tell Us What You Are Planning.','Share the property, project type, timing and what you want to improve.','https://images.unsplash.com/photo-1524758631624-e2822e304c36?auto=format&fit=crop&w=2000&q=90']];}
 private function header(){return $this->c('mjl-header',[$this->img($this->logo,'MJL Renovations','mjl-logo'),$this->c('mjl-nav',[$this->b('Renovations',$this->u('renovations'),'mjl-nav-link'),$this->b('Portfolio',$this->u('renovation-portfolio'),'mjl-nav-link'),$this->b('Process',$this->u('renovation-process'),'mjl-nav-link'),$this->b('Start a Project',$this->u('renovation-contact'),'mjl-btn')],['flex_direction'=>'row','justify_content'=>'flex-end','align_items'=>'center'])],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'flex_direction'=>'row','justify_content'=>'space-between','align_items'=>'center']);}
 private function hero($p){return $this->c('mjl-hero',[$this->c('mjl-hero-copy',[$this->t('<div class="mjl-kicker">'.$p[1].'</div>'),$this->h($p[2],'h1','mjl-h1'),$this->t('<p class="mjl-lead">'.$p[3].'</p>'),$this->c('mjl-actions',[$this->b('Start Your Renovation',$this->u('renovation-contact')),$this->b('View Our Work',$this->u('renovation-portfolio'),'mjl-btn mjl-outline')],['flex_direction'=>'row'])])],['min_height'=>['unit'=>'px','size'=>660],'content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'justify_content'=>'center','background_background'=>'classic','background_image'=>['url'=>$p[4],'id'=>0],'background_position'=>'center center','background_size'=>'cover','background_overlay_background'=>'classic','background_overlay_color'=>'rgba(0,0,0,.58)']);}
 private function services(){ $d=[['Kitchen Renovations','https://images.unsplash.com/photo-1556912167-f556f1f39fdf?auto=format&fit=crop&w=1200&q=85','kitchen-renovations'],['Bathroom Renovations','https://images.unsplash.com/photo-1620626011761-996317b8d101?auto=format&fit=crop&w=1200&q=85','bathroom-renovations'],['Basement Renovations','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=1200&q=85','basement-renovations'],['Whole Home Renovations','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=1200&q=85','whole-home-renovations'],['Custom Home Building','https://images.unsplash.com/photo-1600047509807-ba8f99d2cdde?auto=format&fit=crop&w=1200&q=85','custom-home-building']];$cards=[];foreach($d as $x)$cards[]=$this->c('mjl-card',[$this->img($x[1],$x[0]),$this->h($x[0],'h3'),$this->t('<p>Edit this service description directly in Elementor.</p>'),$this->b('Explore Service',$this->u($x[2]),'mjl-text-btn')]);return $this->c('mjl-section mjl-cream',[$this->t('<div class="mjl-kicker">RENOVATION SERVICES</div>'),$this->h('One Team for the Entire Home','h2','mjl-h2'),$this->c('mjl-grid',$cards,['flex_direction'=>'row'])],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240]]);}
 private function split($title,$text,$img,$rev=false){return $this->c('mjl-section mjl-split',[$this->c('mjl-half',[$this->img($img,$title)]),$this->c('mjl-half',[$this->t('<div class="mjl-kicker">PROJECT DETAIL</div>'),$this->h($title,'h2','mjl-h2'),$this->t('<p class="mjl-body">'.$text.'</p>'),$this->b('Discuss Your Project',$this->u('renovation-contact'),'mjl-text-btn')])],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'flex_direction'=>$rev?'row-reverse':'row','align_items'=>'center']);}
 private function page($slug,$p){$e=[$this->header(),$this->hero($p),$this->c('mjl-trust',[$this->t('<p><strong>ONE TEAM</strong><br>From start to finish</p>'),$this->t('<p><strong>CLEAR COMMUNICATION</strong><br>Regular project updates</p>'),$this->t('<p><strong>PREMIUM CRAFTSMANSHIP</strong><br>Built to last</p>'),$this->t('<p><strong>LOCAL SERVICE</strong><br>Western GTA & Hamilton</p>')],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'flex_direction'=>'row'])];if($slug==='renovations')$e[]=$this->services();$e[]=$this->split('The renovation experience should feel organized','MJL coordinates planning, trades, decisions and communication so the project stays understandable from the first meeting through final walkthrough.',$p[4]);$e[]=$this->split('Built for how you actually live','We balance layout, storage, durability, lighting and finishes to create spaces that look exceptional and work better every day.','https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&w=1800&q=90',true);$e[]=$this->c('mjl-cta',[$this->h('Let’s Discuss the Home You Want to Create','h2','mjl-h2'),$this->b('Request a Consultation',$this->u('renovation-contact'))],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'flex_direction'=>'row','justify_content'=>'space-between','align_items'=>'center']);$e[]=$this->c('mjl-footer',[$this->img($this->logo,'MJL Renovations','mjl-footer-logo'),$this->t('<p>289-828-1933<br>info@mjlconstruction.ca<br>Inquiries accepted 24/7. Consultations by appointment.</p>'),$this->t('<p>Burlington · Oakville · Waterdown · Hamilton · Ancaster · Dundas · Stoney Creek · Milton · Flamborough</p>')],['content_width'=>'boxed','boxed_width'=>['unit'=>'px','size'=>1240],'flex_direction'=>'row']);return $e;}
 public function build(){if(!current_user_can('manage_options'))wp_die('No permission');check_admin_referer('mjl_native_build');if(!did_action('elementor/loaded'))wp_die('Elementor must be active.');foreach($this->pages() as $slug=>$p){$old=get_page_by_path($slug,OBJECT,'page');if($old&&get_post_meta($old->ID,self::FLAG,true)!=='1'&&get_post_meta($old->ID,'_mjl_builder_managed',true)!=='1')continue;$id=wp_insert_post(wp_slash(['ID'=>$old?$old->ID:0,'post_title'=>$p[0],'post_name'=>$slug,'post_type'=>'page','post_status'=>'draft','post_content'=>'']),true);if(is_wp_error($id))continue;update_post_meta($id,'_elementor_edit_mode','builder');update_post_meta($id,'_elementor_template_type','wp-page');update_post_meta($id,'_elementor_version',defined('ELEMENTOR_VERSION')?ELEMENTOR_VERSION:'3.34.2');update_post_meta($id,'_elementor_data',wp_slash(wp_json_encode($this->page($slug,$p))));update_post_meta($id,'_elementor_page_settings',['hide_title'=>'yes']);update_post_meta($id,'_wp_page_template','elementor_canvas');update_post_meta($id,self::FLAG,'1');update_post_meta($id,'_mjl_builder_managed','1');}if(class_exists('\\Elementor\\Plugin'))\\Elementor\\Plugin::$instance->files_manager->clear_cache();wp_safe_redirect(admin_url('edit.php?post_type=page'));exit;}
 public function css(){wp_register_style('mjl-native',false);wp_enqueue_style('mjl-native');wp_add_inline_style('mjl-native',':root{--g:#b9985a;--ink:#151515;--cream:#f8f6f2}.mjl-header{background:#111;padding:12px 28px}.mjl-logo img{width:72px}.mjl-nav{gap:14px}.mjl-nav .elementor-button{background:transparent!important;color:#fff!important;border:0!important;font-size:11px!important;text-transform:uppercase}.mjl-btn .elementor-button{background:var(--g)!important;color:#151515!important;border-radius:0!important;padding:15px 22px!important;font-size:11px!important;font-weight:700!important;text-transform:uppercase;letter-spacing:.1em}.mjl-outline .elementor-button{background:transparent!important;color:#fff!important;border:1px solid #fff!important}.mjl-hero{padding:70px 28px;position:relative}.mjl-hero:before{content:"";position:absolute;inset:0;background:linear-gradient(90deg,rgba(0,0,0,.75),rgba(0,0,0,.15));pointer-events:none}.mjl-hero>.e-con-inner{position:relative}.mjl-hero-copy{max-width:760px}.mjl-kicker{color:var(--g);font-size:12px;letter-spacing:.2em;font-weight:700}.mjl-h1 .elementor-heading-title{font-family:Georgia,serif!important;color:#fff!important;font-size:clamp(52px,7vw,96px)!important;line-height:.96!important}.mjl-h2 .elementor-heading-title{font-family:Georgia,serif!important;font-size:clamp(38px,4vw,64px)!important;line-height:1.02!important}.mjl-lead{color:#fff;font-size:20px}.mjl-actions{gap:14px}.mjl-trust{background:#222;color:#fff;padding:22px 28px;gap:20px}.mjl-trust .elementor-widget-text-editor{width:25%}.mjl-section{padding:95px 28px}.mjl-cream{background:var(--cream)}.mjl-grid{gap:18px;margin-top:38px}.mjl-card{width:20%;background:#fff;border:1px solid #ddd8ce;padding-bottom:24px}.mjl-card img{height:190px;object-fit:cover}.mjl-card .elementor-heading-title,.mjl-card .elementor-widget-text-editor,.mjl-card .elementor-widget-button{margin-left:18px;margin-right:18px}.mjl-card .elementor-heading-title{font-family:Georgia,serif!important;font-size:23px!important}.mjl-text-btn .elementor-button{background:transparent!important;color:#151515!important;border:0!important;border-bottom:1px solid var(--g)!important;border-radius:0!important;padding:0!important;font-weight:700}.mjl-split{gap:60px}.mjl-half{width:50%}.mjl-half img{width:100%;height:470px;object-fit:cover}.mjl-body{font-size:18px;line-height:1.7}.mjl-cta{background:#222;color:#fff;padding:70px 28px;gap:30px}.mjl-cta .elementor-heading-title{color:#fff!important}.mjl-footer{background:#0d0d0d;color:#ddd;padding:55px 28px;gap:50px}.mjl-footer-logo img{width:82px}.mjl-footer>.e-con-inner>*{width:33.33%}@media(max-width:900px){.mjl-nav-link{display:none}.mjl-grid{flex-wrap:wrap}.mjl-card{width:calc(50% - 9px)}.mjl-split{gap:30px}}@media(max-width:767px){.mjl-header{padding:10px 16px}.mjl-logo img{width:55px}.mjl-hero{padding:60px 18px;min-height:600px!important}.mjl-h1 .elementor-heading-title{font-size:48px!important}.mjl-section{padding:65px 18px}.mjl-trust,.mjl-grid,.mjl-split,.mjl-cta,.mjl-footer{flex-direction:column!important}.mjl-trust .elementor-widget-text-editor,.mjl-card,.mjl-half,.mjl-footer>.e-con-inner>*{width:100%!important}.mjl-half img{height:320px}}');}
}
